use actix_web::{web, App, HttpResponse, HttpServer};
use reqwest;

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/", web::get().to(handle_request))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}

async fn handle_request(req: web::Query<web::Query<String>>) -> HttpResponse {
    let url = req.into_inner();
    match reqwest::get(&url).await {
        Ok(response) => {
            let body = response.text().await.unwrap();
            HttpResponse::Ok().body(body)
        },
        Err(_) => HttpResponse::BadRequest().body("Error fetching URL")
    }
}